import { useRef, useEffect, useState } from 'react';

export default function Timeline() {
  const timelineRef = useRef(null);
  const [visibleItems, setVisibleItems] = useState({});

  const [timelineData, setTimelineData] = useState([]); 

  // 타임라인 데이터 (기존 내용 기반)
  const timeline = [
    {
      id: 1,
      type: 'current',
      date: '2024.09 - 현재',
      title: '[현재 하고 있는 것]',
      description: '[무엇을 하고 있는지, 어떤 목표를 가지고 있는지]',
      details: ['[구체적인 활동 1]', '[구체적인 활동 2]']
    },
    {
      id: 2,
      type: 'activity',
      date: '2024.06 - 2024.08',
      title: '[여름에 한 활동]',
      description: '[어떤 활동을 했는지, 왜 했는지]',
      details: ['[배운 점 1]', '[배운 점 2]']
    },
    {
      id: 3,
      type: 'project',
      date: '2024.03 - 2024.06',
      title: '[프로젝트나 공모전]',
      description: '[무엇을 했는지, 어떤 역할이었는지]',
      details: ['[성과 1]', '[성과 2]', '[느낀 점]']
    },
    {
      id: 4,
      type: 'activity',
      date: '2023.09 - 2023.12',
      title: '[학교 활동이나 인턴십]',
      description: '[어떤 활동이었는지]',
      details: ['[배운 기술이나 역량]', '[인상 깊었던 경험]']
    },
    {
      id: 5,
      type: 'activity',
      date: '2023.03 - 2023.08',
      title: '[동아리나 스터디]',
      description: '[어떤 활동을 했는지]',
      details: ['[활동 내용]', '[얻은 것]']
    },
    {
      id: 6,
      type: 'education',
      date: '2022',
      title: '[처음 코딩/기획을 시작한 계기]',
      description: '[어떻게 시작하게 되었는지, 첫 느낌은 어땠는지] [이때부터 어떤 마음가짐으로 공부했는지]',
      details: []
    },
    {
      id: 7,
      type: 'education',
      date: '2021.03',
      title: '가천대학교 컴퓨터공학과 입학',
      description: '[왜 이 학과를 선택했는지, 입학 전 기대했던 것]',
      details: []
    }
  ];

  // Intersection Observer로 타임라인 아이템 애니메이션
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisibleItems((prev) => ({
              ...prev,
              [entry.target.dataset.id]: true,
            }));
          }
        });
      },
      { threshold: 0.2 }
    );

    const items = document.querySelectorAll('.timeline-item');
    items.forEach((item) => observer.observe(item));

    return () => {
      items.forEach((item) => observer.unobserve(item));
    };
  }, [timeline]);

  const getTypeIcon = (type) => {
    switch (type) {
      case 'current':
        return (
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="10"/>
            <polyline points="12 6 12 12 16 14"/>
          </svg>
        );
      case 'project':
        return (
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>
          </svg>
        );
      case 'activity':
        return (
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/>
          </svg>
        );
      case 'education':
        return (
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M22 10v6M2 10l10-5 10 5-10 5z"/>
            <path d="M6 12v5c3 3 9 3 12 0v-5"/>
          </svg>
        );
      default:
        return (
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="4"/>
          </svg>
        );
    }
  };

  const getTypeLabel = (type) => {
    switch (type) {
      case 'current': return '진행 중';
      case 'project': return '프로젝트';
      case 'activity': return '활동';
      case 'education': return '교육';
      default: return '';
    }
  };

  return (
    <div className="timeline-page">
      <div className="container">
        {/* Page Header */}
        <header className="page-header">
          <h1>Timeline</h1>
          <p className="page-subtitle">
            지금까지의 여정을 시간순으로 정리했습니다.
          </p>
        </header>

        {/* Timeline */}
        <div ref={timelineRef} className="timeline-container">
          <div className="timeline-line"></div>

          {timeline.map((item, index) => (
            <div
              key={item.id}
              data-id={item.id}
              className={`timeline-item ${item.type} ${visibleItems[item.id] ? 'visible' : ''}`}
              style={{ animationDelay: `${index * 0.1}s` }}
            >
              <div className="timeline-marker">
                <div className={`marker-dot ${item.type}`}>
                  {getTypeIcon(item.type)}
                </div>
              </div>

              <div className="timeline-content">
                <div className="timeline-header">
                  <span className="timeline-date">{item.date}</span>
                  <span className={`timeline-type ${item.type}`}>
                    {getTypeLabel(item.type)}
                  </span>
                </div>

                <h3 className="timeline-title">{item.title}</h3>
                <p className="timeline-description">{item.description}</p>

                {item.details && item.details.length > 0 && (
                  <ul className="timeline-details">
                    {item.details.map((detail, idx) => (
                      <li key={idx}>{detail}</li>
                    ))}
                  </ul>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* 기억에 남는 순간 */}
        <section className="memorable-section">
          <h2>기억에 남는 순간</h2>
          <div className="memorable-content">
            <div className="quote-icon">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="currentColor" opacity="0.1">
                <path d="M6 17h3l2-4V7H5v6h3zm8 0h3l2-4V7h-6v6h3z"/>
              </svg>
            </div>
            <p>
              [개발/기획하면서 가장 기억에 남는 순간]
            </p>
            <p>
              [그때 느꼈던 감정과 배운 점]
            </p>
          </div>
        </section>
      </div>
    </div>
  );
}
